// Pull both ensures (the sequence-equality clause) into the proof context
// so z3 can line up the two runs' postconditions.
assert(post1_self_@ == pre_self_@.subrange(0, start as int)
    + pre_self_@.subrange(end as int, pre_self_@.len() as int));
assert(post2_self_@ == pre_self_@.subrange(0, start as int)
    + pre_self_@.subrange(end as int, pre_self_@.len() as int));

// Both views equal the same `subrange + subrange` expression of `pre_self_`,
// hence they are equal as sequences (extensionality closes any residual gap).
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);
